module sram_cell (  
    input wire write_enable,  
    input wire data_in,  
    input wire clock,  
    output reg data_out  
);  
    reg obf_stored_bit;  

    always @(posedge clock) begin  
        if (write_enable) begin  
            obf_stored_bit <= data_in;  
        end  
    end  

    always @(*) begin  
        data_out = obf_stored_bit;  
    end  
endmodule
